const DEFAULT_POLL_INTERVAL_MS = 1500;
export async function createAgentSession(opts) {
    const url = `${opts.serviceUrl}/api/studio/sessions`;
    const res = await fetch(url, {
        method: "POST",
        headers: {
            Authorization: `Bearer ${opts.apiKey}`,
            "Content-Type": "application/json",
            ...opts.extraHeaders,
        },
        body: JSON.stringify({ sessionId: opts.sessionId }),
    });
    if (!res.ok) {
        throw new Error(`createAgentSession failed (${res.status}): ${await res.text()}`);
    }
    return (await res.json());
}
/**
 * Push an event into a session's event stream. Use this to send commands
 * (e.g. "agent:navigate") to the browser tab paired with `sessionId`.
 * Event types and data shapes come from the typed `AgentEventDataMap`
 * union.
 */
export async function pushAgentSessionEvent(client, event) {
    const url = `${client.serviceUrl}/api/studio/events`;
    const res = await fetch(url, {
        method: "POST",
        headers: {
            Authorization: `Bearer ${client.apiKey}`,
            "Content-Type": "application/json",
        },
        body: JSON.stringify({
            session: client.sessionId,
            type: event.type,
            data: event.data,
        }),
    });
    if (!res.ok) {
        throw new Error(`pushAgentSessionEvent failed (${res.status}): ${await res.text()}`);
    }
    return (await res.json());
}
/**
 * Continuously poll a session's event stream. Each poll request is short-
 * lived (Vercel-friendly) and asks for events strictly after `since`. The
 * cursor advances after each successful poll.
 *
 * The loop runs until `abortSignal` fires. Network errors are surfaced via
 * `onError` and the loop continues; transient failures should not terminate
 * the channel.
 */
export async function pollAgentSessionEvents(opts) {
    const interval = opts.intervalMs ?? DEFAULT_POLL_INTERVAL_MS;
    let since = opts.startCursor ?? null;
    while (!opts.abortSignal.aborted) {
        try {
            const url = new URL(`${opts.serviceUrl}/api/studio/events`);
            url.searchParams.set("session", opts.sessionId);
            if (since) {
                url.searchParams.set("since", since);
            }
            const res = await fetch(url.toString(), {
                headers: { Authorization: `Bearer ${opts.apiKey}` },
                signal: opts.abortSignal,
            });
            if (res.ok) {
                const body = (await res.json());
                for (const event of body.events) {
                    opts.onEvent(event);
                    since = event.id;
                }
            }
            else if (opts.onError) {
                opts.onError(new Error(`agent-session poll failed (${res.status})`));
            }
        }
        catch (err) {
            if (opts.abortSignal.aborted) {
                return;
            }
            if (opts.onError) {
                opts.onError(err instanceof Error ? err : new Error(String(err)));
            }
        }
        await new Promise((resolve) => {
            const timer = setTimeout(resolve, interval);
            opts.abortSignal.addEventListener("abort", () => {
                clearTimeout(timer);
                resolve();
            }, { once: true });
        });
    }
}
export async function navigateStudio(client, path) {
    return pushAgentSessionEvent(client, {
        type: "agent:navigate",
        data: { path },
    });
}
